changeSet.sql:
CREATE TABLE game_recommender.user_preferences ( id UUID PRIMARY KEY, user_id UUID NOT NULL, ai_agent_id UUID, game_id BIGINT, game_name VARCHAR(255), reasoning TEXT, generated_at TIMESTAMP(6), tags JSONB, created_at TIMESTAMP(6) NOT NULL, updated_at TIMESTAMP(6) NOT NULL );
-- FK on users ALTER TABLE game_recommender.user_preferences ADD CONSTRAINT fk_user_preferences_user_id FOREIGN KEY (user_id) REFERENCES game_recommender.users (id);
-- FK on ai_agents ALTER TABLE game_recommender.user_preferences ADD CONSTRAINT fk_user_preferences_ai_agent_id FOREIGN KEY (ai_agent_id) REFERENCES game_recommender.ai_agents (id);
